data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist in the framework. Here's what you actually use for boundary checks:

| Need | MSTest Approach |
|------|----------------|
| Value comparison | `Assert.IsTrue(val > x)` or use `Assert.AreEqual` |
| Float equality | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

For richer assertions, consider **FluentAssertions** (`value.Should().BeInRange(lo, hi)`).

Here's a proper MSTest test class for your code:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calc.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_ResultIsClamped_NeverExceeds100()
    {
        var result = _calc.NormalizeScore(150, 100);

        // No Assert.IsLessThanOrEqual — use Assert.IsTrue
        Assert.IsTrue(result <= 100.0, $"Expected <= 100 but got {result}");
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ReturnsInRange()
    {
        var result = _calc.NormalizeScore(50, 200);

        // Boundary check: result should be in [0, 100]
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Score {result} out of expected range [0, 100]");
        Assert.AreEqual(25.0, result, 0.001);
    }
}
```

**Key takeaways:**
- Use `Assert.AreEqual(expected, actual, delta)` for floating-point comparisons
- Use `Assert.IsTrue(expr)` with a message for range/boundary checks
- Use `Assert.ThrowsException<T>` for invalid input validation
